const body = $input.first().json.body;

const paymentId = body.payment_id;
const amount = body.amount;
const clientName = body.client_name || 'Customer';
const clientEmail = body.client_email || '';
const websiteId = body.website_id || '';
const isSubscription = body.is_subscription || false;

if (!paymentId || !amount) {
  throw new Error('payment_id and amount are required');
}

const orderId = 'PAY-' + paymentId + '-' + Date.now();

const payload = {
  transaction_details: {
    order_id: orderId,
    gross_amount: Number(amount)
  },
  customer_details: {
    first_name: clientName,
    email: clientEmail
  },
  item_details: [
    {
      id: websiteId || 'webren-service',
      price: Number(amount),
      quantity: 1,
      name: 'Webren ID Website Service'
    }
  ]
};

if (isSubscription) {
  payload.credit_card = { save_card: true };
  payload.recurring = { required: true, interval_unit: 'month' };
  payload.user_id = 'webren-client-' + paymentId;
}

return {
  json: {
    orderId: orderId,
    paymentId: paymentId,
    payloadStr: JSON.stringify(payload)
  }
};

const midtransResponse = $input.first().json;
const orderId = $('Build Payload').item.json.orderId;
const paymentId = $('Build Payload').item.json.paymentId;

const snapToken = midtransResponse.token;

if (!snapToken) {
  throw new Error('Midtrans did not return a snap token: ' + JSON.stringify(midtransResponse));
}

return {
  json: {
    snap_token: snapToken,
    order_id: orderId,
    payment_id: paymentId
  }
};
